<?php
 namespace League\CommonMark\Extension\TableOfContents; use League\CommonMark\Block\Parser\BlockParserInterface; use League\CommonMark\ContextInterface; use League\CommonMark\Cursor; use League\CommonMark\Extension\TableOfContents\Node\TableOfContentsPlaceholder; use League\CommonMark\Util\ConfigurationAwareInterface; use League\CommonMark\Util\ConfigurationInterface; final class TableOfContentsPlaceholderParser implements BlockParserInterface, ConfigurationAwareInterface { private $config; public function parse(ContextInterface $context, Cursor $cursor): bool { $placeholder = $this->config->get('table_of_contents/placeholder'); if ($placeholder === null) { return false; } if ($cursor->match('/^' . \preg_quote($placeholder, '/') . '$/') === null) { return false; } $context->addBlock(new TableOfContentsPlaceholder()); return true; } public function setConfiguration(ConfigurationInterface $configuration) { $this->config = $configuration; } } 